---
import {
  renderSemanticIconSvg,
  type IconLibraryName,
  type SemanticIconName,
} from "@bejamas/semantic-icons";
import { resolveActiveIconLibrary } from "@/registry/bejamas-juno/lib/icons";
import { cn } from "@/registry/bejamas-juno/lib/utils";

type Props = {
  name: SemanticIconName;
  library?: IconLibraryName;
  class?: string;
  "aria-hidden"?: "true" | "false";
} & Record<string, string | number | boolean | undefined>;

const {
  name,
  library: providedLibrary,
  class: className = "",
  "aria-hidden": ariaHidden = "true",
  ...rest
} = Astro.props as Props;

const library = resolveActiveIconLibrary(Astro, providedLibrary);
const markup = renderSemanticIconSvg(library, name, {
  class: cn("cn-semantic-icon", className),
  "aria-hidden": ariaHidden,
  "data-semantic-icon": name,
  "data-icon-library": library,
  ...rest,
});
---

<Fragment set:html={markup} />
